-- Create "purchase_returns" table
CREATE TABLE "purchase_returns" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "return_no" character varying NOT NULL,
  "supplier_name" character varying NOT NULL,
  "status" character varying NOT NULL DEFAULT 'DRAFT',
  "returned_at" timestamptz NOT NULL,
  "posted_at" timestamptz NULL,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "business_record_id" bigint NULL,
  "purchase_receipt_id" bigint NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "purchase_returns_business_records_purchase_returns" FOREIGN KEY ("business_record_id") REFERENCES "business_records" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "purchase_returns_purchase_receipts_purchase_returns" FOREIGN KEY ("purchase_receipt_id") REFERENCES "purchase_receipts" ("id") ON UPDATE NO ACTION ON DELETE SET NULL
);
-- Create index "purchasereturn_business_record_id" to table: "purchase_returns"
CREATE INDEX "purchasereturn_business_record_id" ON "purchase_returns" ("business_record_id");
-- Create index "purchasereturn_purchase_receipt_id" to table: "purchase_returns"
CREATE INDEX "purchasereturn_purchase_receipt_id" ON "purchase_returns" ("purchase_receipt_id");
-- Create index "purchasereturn_return_no" to table: "purchase_returns"
CREATE UNIQUE INDEX "purchasereturn_return_no" ON "purchase_returns" ("return_no");
-- Create index "purchasereturn_returned_at" to table: "purchase_returns"
CREATE INDEX "purchasereturn_returned_at" ON "purchase_returns" ("returned_at");
-- Create index "purchasereturn_status" to table: "purchase_returns"
CREATE INDEX "purchasereturn_status" ON "purchase_returns" ("status");
-- Create "purchase_return_items" table
CREATE TABLE "purchase_return_items" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "quantity" numeric(20,6) NOT NULL,
  "unit_price" numeric(20,6) NULL,
  "amount" numeric(20,6) NULL,
  "source_line_no" character varying NULL,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "lot_id" bigint NULL,
  "material_id" bigint NOT NULL,
  "purchase_receipt_item_id" bigint NULL,
  "return_id" bigint NOT NULL,
  "unit_id" bigint NOT NULL,
  "warehouse_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "purchase_return_items_inventory_lots_purchase_return_items" FOREIGN KEY ("lot_id") REFERENCES "inventory_lots" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_return_items_materials_purchase_return_items" FOREIGN KEY ("material_id") REFERENCES "materials" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_return_items_purchase_receipt_items_purchase_return_it" FOREIGN KEY ("purchase_receipt_item_id") REFERENCES "purchase_receipt_items" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "purchase_return_items_purchase_returns_items" FOREIGN KEY ("return_id") REFERENCES "purchase_returns" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_return_items_units_purchase_return_items" FOREIGN KEY ("unit_id") REFERENCES "units" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_return_items_warehouses_purchase_return_items" FOREIGN KEY ("warehouse_id") REFERENCES "warehouses" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_return_items_amount_non_negative" CHECK ((amount IS NULL) OR (amount >= (0)::numeric)),
  CONSTRAINT "purchase_return_items_quantity_positive" CHECK (quantity > (0)::numeric),
  CONSTRAINT "purchase_return_items_unit_price_non_negative" CHECK ((unit_price IS NULL) OR (unit_price >= (0)::numeric))
);
-- Create index "purchasereturnitem_lot_id" to table: "purchase_return_items"
CREATE INDEX "purchasereturnitem_lot_id" ON "purchase_return_items" ("lot_id");
-- Create index "purchasereturnitem_material_id" to table: "purchase_return_items"
CREATE INDEX "purchasereturnitem_material_id" ON "purchase_return_items" ("material_id");
-- Create index "purchasereturnitem_purchase_receipt_item_id" to table: "purchase_return_items"
CREATE INDEX "purchasereturnitem_purchase_receipt_item_id" ON "purchase_return_items" ("purchase_receipt_item_id");
-- Create index "purchasereturnitem_return_id" to table: "purchase_return_items"
CREATE INDEX "purchasereturnitem_return_id" ON "purchase_return_items" ("return_id");
-- Create index "purchasereturnitem_return_id_source_line_no" to table: "purchase_return_items"
CREATE UNIQUE INDEX "purchasereturnitem_return_id_source_line_no" ON "purchase_return_items" ("return_id", "source_line_no") WHERE ((source_line_no IS NOT NULL) AND ((source_line_no)::text <> ''::text));
-- Create index "purchasereturnitem_warehouse_id" to table: "purchase_return_items"
CREATE INDEX "purchasereturnitem_warehouse_id" ON "purchase_return_items" ("warehouse_id");
